// Configure the LIN frame with the ID 0x01 as response of the slave and initialize the value of all response bytes to zero.

on preStart

{
  long i;
  byte responseData [8];

  for(i = 0; i < 8; i++)
  {
    responseData [i] = 0;
  }

  linConfigureResponse(0x01, 8, responseData);
}
